//! High-performance design matrix construction for statistical models
//!
//! This crate provides column-oriented design matrix builders that fuse
//! transformations to eliminate intermediate allocations and leverage
//! parallel computation for construction.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::Array2;
use formula::ModelSpec;

/// Design matrix construction errors
#[derive(thiserror::Error, Debug)]
pub enum MatrixError {
    /// Data dimension mismatch
    #[error("Data dimension error: {0}")]
    Dimension(String),
    /// Variable not found in data
    #[error("Variable not found: {0}")]
    VariableNotFound(String),
}

/// Column-major design matrix builder
pub struct Builder {
    n_rows: usize,
    columns: Vec<Vec<f64>>,
}

impl Builder {
    /// Create a new builder for the given number of observations
    pub fn new(n_rows: usize) -> Self {
        Self {
            n_rows,
            columns: Vec::new(),
        }
    }

    /// Add an intercept column (all ones)
    pub fn add_intercept(&mut self) {
        self.columns.push(vec![1.0; self.n_rows]);
    }

    /// Add a continuous variable column
    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(
                format!("Expected {} rows, got {}", self.n_rows, values.len())
            ));
        }
        self.columns.push(values);
        Ok(())
    }

    /// Build the final design matrix
    pub fn build(self) -> Array2<f64> {
        if self.columns.is_empty() {
            return Array2::zeros((self.n_rows, 0));
        }

        let n_cols = self.columns.len();
        let mut matrix = Array2::zeros((self.n_rows, n_cols));

        for (col_idx, column) in self.columns.into_iter().enumerate() {
            for (row_idx, value) in column.into_iter().enumerate() {
                matrix[[row_idx, col_idx]] = value;
            }
        }

        matrix
    }
}

/// Build design matrix from model specification and data
pub fn build_design_matrix(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
    // TODO: Implement full design matrix construction in Sprint 2
    // For now, return a simple 2x1 intercept matrix for testing
    let mut builder = Builder::new(2);
    builder.add_intercept();
    Ok(builder.build())
}

