//! High-level statistical modeling API for Rust
//!
//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
//! and `Glm` (Generalized Linear Models), integrating lower-level crates
//! to provide a complete modeling workflow.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::Array2;

/// Statistical modeling errors
#[derive(thiserror::Error, Debug)]
pub enum ModelError {
    /// Linear algebra computation error
    #[error("Linear algebra error: {0}")]
    LinearAlgebra(String),
    /// Invalid model specification
    #[error("Invalid model: {0}")]
    InvalidModel(String),
}

/// Common trait for all fitted models
pub trait Fit {
    /// Get model coefficients
    fn coefficients(&self) -> &[f64];

    /// Get fitted values
    fn fitted(&self) -> &[f64];

    /// Get residuals
    fn residuals(&self) -> &[f64];

    /// Get model summary
    fn summary(&self) -> ModelSummary;
}

/// Model summary information
#[derive(Debug)]
pub struct ModelSummary {
    /// Coefficient table
    pub coefficients: Vec<CoefficientRow>,
}

/// A row in the coefficient table
#[derive(Debug)]
pub struct CoefficientRow {
    /// Variable name
    pub name: String,
    /// Estimated coefficient
    pub estimate: f64,
    /// Standard error
    pub std_error: f64,
    /// t-statistic
    pub t_value: f64,
    /// p-value
    pub p_value: f64,
}

/// Linear model fitting
pub struct Lm;

/// Fitted linear model results
#[derive(Debug)]
pub struct LmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    vcov: Array2<f64>,
}

impl Lm {
    /// Fit a linear model using QR decomposition
    pub fn fit(_x: &Array2<f64>, _y: &[f64]) -> Result<LmFit, ModelError> {
        // TODO: Implement QR-based OLS solver in Sprint 3
        // For now, return a placeholder result for testing
        Ok(LmFit {
            coefficients: vec![1.0, 0.5],
            fitted_values: vec![1.5, 2.0],
            residuals: vec![0.1, -0.2],
            vcov: Array2::eye(2),
        })
    }
}

impl Fit for LmFit {
    fn coefficients(&self) -> &[f64] {
        &self.coefficients
    }

    fn fitted(&self) -> &[f64] {
        &self.fitted_values  
    }

    fn residuals(&self) -> &[f64] {
        &self.residuals
    }

    fn summary(&self) -> ModelSummary {
        // TODO: Implement proper statistical inference in Sprint 3
        ModelSummary {
            coefficients: vec![
                CoefficientRow {
                    name: "Intercept".to_string(),
                    estimate: self.coefficients[0],
                    std_error: 0.1,
                    t_value: 10.0,
                    p_value: 0.001,
                }
            ],
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::Array2;

    #[test]
    fn test_lm_fit_basic() {
        let x = Array2::eye(2);
        let y = vec![1.0, 2.0];

        let result = Lm::fit(&x, &y);
        assert!(result.is_ok());

        let fit = result.unwrap();
        assert_eq!(fit.coefficients().len(), 2);
        assert_eq!(fit.fitted().len(), 2);
        assert_eq!(fit.residuals().len(), 2);
    }

    #[test]
    fn test_lm_summary() {
        let x = Array2::eye(2);
        let y = vec![1.0, 2.0];

        let fit = Lm::fit(&x, &y).unwrap();
        let summary = fit.summary();

        assert!(!summary.coefficients.is_empty());
        assert_eq!(summary.coefficients[0].name, "Intercept");
    }
}

